import{_ as t,o,c as a,a3 as n}from"./chunks/framework.CjquFG0V.js";const l=JSON.parse('{"title":"45. Workers Compensation Make Up Pay","description":"","frontmatter":{"title":"45. Workers Compensation Make Up Pay","eba":"Doctors in Training 2022-2026","topics":["wages","accident-pay","preliminary"]},"headers":[],"relativePath":"ebas/doctors-in-training/remuneration/45-workers-compensation-make-up-pay.md","filePath":"ebas/doctors-in-training/remuneration/45-workers-compensation-make-up-pay.md"}'),r={name:"ebas/doctors-in-training/remuneration/45-workers-compensation-make-up-pay.md"};function i(s,e,p,c,h,m){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="_45-workers-compensation-make-up-pay" tabindex="-1">45. Workers Compensation Make Up Pay <a class="header-anchor" href="#_45-workers-compensation-make-up-pay" aria-label="Permalink to &quot;45. Workers Compensation Make Up Pay&quot;">​</a></h1><p><strong>45.1</strong> Entitlement to Workers Compensation Make-up Pay</p><p><strong>(a)</strong> A Doctor on receiving payment of weekly compensation under the WIRC Act is entitled to Workers Compensation Make-up Pay for up to a maximum aggregate period of 39 weeks for any one injury or illness.</p><p><strong>(b)</strong> No weekly payments of Workers Compensation Make-up Pay apply:</p><p><strong>(i)</strong> within the first two weeks of new employment;</p><p><strong>(ii)</strong> during the first five working days of incapacity;</p><p><strong>(iii)</strong> once the Doctor ends employment with the Health Service;</p><p><strong>(iv)</strong> once the Health Service terminates the employment of the Doctor for serious or wilful misconduct;</p><p><strong>(v)</strong> once there is a cessation or redemption of weekly compensation payments;</p><p><strong>(vi)</strong> for industrial diseases contracted by a gradual process or injury subject to recurrence, aggravation, or acceleration, unless the Doctor has been employed at the time of the incapacity for a minimum period of one month;</p><p><strong>(vii)</strong> for any period of paid annual leave, long service leave or for any paid public holiday.</p><p><strong>(c)</strong> In order to qualify for the continuance of Workers Compensation Make-up Pay on termination a Doctor must, if required by the Health Service, provide evidence of the continuing payment of weekly payments of compensation.</p><p><strong>(d)</strong> On engagement, a Doctor may be required to declare all workers compensation and/or accident claims made under the WIRC Act in the previous 5 years and in the event of defaults or inaccurate information being deliberately and knowingly declared the Health Service may require the Doctor to forfeit their entitlement to Workers Compensation Make-up Pay under this Agreement.</p><p><strong>45.2</strong> Payment Calculation – Total Incapacity</p><p><strong>(a)</strong> Where a Doctor is deemed totally incapacitated under the WIRC Act, the Doctor is entitled to a weekly payment of an amount representing the difference between:</p><p><strong>(i)</strong> the total amount of compensation paid under the WIRC Act during the period of incapacity for the week; and</p><p><strong>(ii)</strong> the weekly ordinary rate of pay set out in <a href="/eba/ebas/doctors-in-training/appendices/2-doctors-in-training-remuneration-allowances-and-deductions.html">Appendix 2</a>, and any over- Agreement payment being paid to the Doctor at the date of the injury and which would have been payable for the Doctor’s classification for the week in question if they had been performing their normal duties.</p><p><strong>45.3</strong> Payment Calculation – Partial Incapacity</p><p><strong>(a)</strong> Where a Doctor is deemed partially incapacitated under the WIRC Act, the Doctor is entitled to weekly payment of an amount representing the difference between:</p><p><strong>(i)</strong> the total amount of compensation paid under the WIRC Act during the period of incapacity for the week, together with the average weekly amount they are earning; and</p><p><strong>(ii)</strong> the weekly rate as set out in <a href="/eba/ebas/doctors-in-training/appendices/2-doctors-in-training-remuneration-allowances-and-deductions.html">Appendix 2</a> and any over-Agreement payment being paid to the Doctor at the date of injury and which would have been payable for the Doctor’s classification for the week in question if they had been performing their normal duties.</p><p><strong>45.4</strong> Payment for Part of a Week</p><p>Where the Doctor is incapacitated for part of a week the Doctor must receive pro-rata Workers Compensation Make-up Pay.</p><p><strong>45.5</strong> Notice of Injury</p><p>A Doctor must ensure that notice in writing of their injury is given to their Health Service as soon as reasonably practicable after the injury or illness.</p><p><strong>45.6</strong> Variations in Compensation Rates</p><p>Any changes in compensation rates under the WIRC Act must not increase the amount of Workers Compensation Make-up Pay above the amount that would have been payable had the rates of compensation remained unchanged.</p><p><strong>45.7</strong> Civil Damages</p><p><strong>(a)</strong> A Doctor receiving, or who has received, Workers Compensation Make-up Pay must advise their Health Service of any action they may institute or any claim they make for damages. The Doctor must, if requested, provide an authority to the Health Service entitling the Health Service to a charge upon any money payable pursuant to any judgment or settlement on that injury.</p><p><strong>(b)</strong> Where a Doctor obtains a judgment or settlement for damages in respect of an injury for which they have received Workers Compensation Make-up Pay the liability to pay Workers Compensation Make-up Pay must cease from the date of the judgment or settlement. If the judgment or settlement for damages is not reduced by the amount of Workers Compensation Make-up Pay made by the Health Service, the Doctor will pay to the Health Service any amount of Workers Compensation Make-up Pay already received in respect of that injury.</p><p><strong>45.8</strong> Medical Examination</p><p>Where, in accordance with the WIRC Act, a medical referee gives a certificate as to the condition of the Doctor and their fitness for work or specifies work for which the Doctor is fit and such work is made available by the Health Service and is refused by the Doctor or the Doctor fails to commence the work, Workers Compensation Make-up Pay must cease from the date of such refusal or failure to commence the work.</p><p>Plain language terms: accident makeup pay, workers comp.</p>',33)])])}const u=t(r,[["render",i]]);export{l as __pageData,u as default};
